mcCloze.css:
/* Card Base */
.card {
    font-family: "Noto Sans Bengali", "Noto Sans", Arial, sans-serif;
    font-size: 18px;
    text-align: center;
    padding: 10px;
    max-width: 600px;
    margin: 0 auto;
    min-height: 400px;
    position: relative;
}

.cloze-sentence {
    font-size: 26px;
    line-height: 1.5;
    margin: 15px 0;
    font-weight: 500;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    min-height: 60px;
    height: auto;
}

.sentence-text { display: inline-block; }

.audio-placeholder {
    display: inline-flex;
    align-items: center;
    width: 30px;
    height: 30px;
    min-width: 30px;
    min-height: 30px;
    visibility: hidden;
}

.audio-inline {
    display: inline-flex;
    align-items: center;
    width: 30px;
    height: 30px;
    min-width: 30px;
    min-height: 30px;
    justify-content: center;
}

.audio-inline audio,
.audio-inline button,
.audio-inline svg,
.audio-inline span,
.audio-inline a {
    max-width: 30px;
    max-height: 30px;
}

.cloze {
    font-weight: bold;
    color: #0066cc;
    background-color: #e6f2ff;
    padding: 2px 6px;
    border-radius: 4px;
    display: inline-block;
    min-height: 1em;
    line-height: 1.4;
}

.night_mode .cloze {
    color: #66b3ff;
    background-color: #1a3a52;
}

.level-indicator {
    display: inline-block;
    padding: 2px 6px;
    border-radius: 10px;
    font-size: 11px;
    font-weight: bold;
    opacity: 0.8;
    margin-right: 10px;
}

.level-1 { background-color: #4CAF50; color: white; }
.level-2 { background-color: #8BC34A; color: white; }
.level-3 { background-color: #FFC107; color: #333; }
.level-4 { background-color: #FF9800; color: white; }
.level-5 { background-color: #F44336; color: white; }

.options-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
    margin: 20px 0;
    min-height: 200px;
}

.options-grid:has(.option:nth-child(3):last-child),
.options-grid:has(.option:nth-child(2):last-child),
.options-grid:has(.option:nth-child(1):last-child) {
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
}

.option {
    font-size: 22px;
    padding: 20px 15px;
    border: 2px solid #ddd;
    border-radius: 8px;
    cursor: default;
    min-height: 80px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.night_mode .option { border-color: #555; }

.answer .option.correct {
    border-color: #4CAF50;
    border-width: 3px;
}

.answer .option.incorrect {
    border-color: #999;
    opacity: 0.7;
}

.option-text-container {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    margin-bottom: 4px;
    flex-wrap: wrap;
}

.option-text { font-weight: 500; }

.option-marker {
    font-size: 20px;
    font-weight: bold;
}

.option.correct .option-marker { color: #4CAF50; }
.option.incorrect .option-marker { color: #f44336; }

.option-details {
    font-size: 13px;
    color: #666;
    line-height: 1.2;
    text-align: center;
    width: 100%;
    padding: 0 5px;
    margin-top: 4px;
}

.night_mode .option-details { color: #999; }

.option-audio {
    display: inline-block;
    opacity: 0.8;
}

.option-audio audio,
.option-audio button,
.option-audio svg {
    max-width: 24px;
    max-height: 24px;
}

.no-autoplay audio:first-child { display: none; }

.notes,
.explanation {
    margin: 15px 0;
    padding: 10px;
    text-align: left;
    font-size: 16px;
    line-height: 1.5;
}

.notes-label,
.explanation-label {
    font-weight: bold;
    margin-bottom: 4px;
    font-size: 14px;
}

.focus-type {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 4px;
    font-size: 11px;
    font-weight: bold;
    margin: 5px 0;
    opacity: 0.8;
    height: 20px;
    line-height: 16px;
}

.focus-type.GRAMMAR {
    background-color: #e8f5e9;
    color: #2e7d32;
}

.night_mode .focus-type.GRAMMAR {
    background-color: #1b3a1d;
    color: #66bb6a;
}

.focus-type.VOCABULARY {
    background-color: #f3e5f5;
    color: #6a1b9a;
}

.night_mode .focus-type.VOCABULARY {
    background-color: #3a1b4a;
    color: #ba68c8;
}

.metadata {
    margin-top: 15px;
    font-size: 11px;
    color: #999;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-wrap: wrap;
    gap: 5px;
}

.source { margin-left: 5px; }

@media (max-width: 600px) {
    .card { padding: 5px; min-height: 350px; }
    .cloze-sentence { font-size: 24px; margin: 10px 0; min-height: 50px; }
    .metadata { margin-top: 10px; flex-direction: column; gap: 3px; }
    .options-grid { gap: 6px; margin: 15px 0; min-height: 180px; }
    .option { font-size: 20px; padding: 18px 12px; min-height: 75px; }
    .option-details { font-size: 12px; }
    .notes, .explanation { padding: 8px; font-size: 15px; }
}
